#!/usr/bin/env bash
# editing-comping-quantize-pitch-c.sh — Editing（comping / quantize / pitch-correct / time-align —— 整理成'可混'素材） SOP walkthrough for 音乐制作 / 混音.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="音乐制作 / 混音"
WORKFLOW="Editing（comping / quantize / pitch-correct / time-align —— 整理成'可混'素材）"

usage() {
  cat <<EOF
editing-comping-quantize-pitch-c.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./editing-comping-quantize-pitch-c.sh             # interactive
  ./editing-comping-quantize-pitch-c.sh --dry-run
  ./editing-comping-quantize-pitch-c.sh --json
  ./editing-comping-quantize-pitch-c.sh --explain
  ./editing-comping-quantize-pitch-c.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "Editing（comping / quantize / pitch-correct / time-align —— 整理成"可混"素材）" 工作流。

一句话: 把原始多 take 录音整理成干净、对齐、修过音、可以直接进混音的素材 —— 拼最佳表演（comping）、对齐时值（quantize/time-align）、修音高（pitch-correct），在"修到位"与"保留人味/pocket"之间取舍。(evidence: [T03-S002])

入门 SOP 共 5 步, 失败模式自检 3 项。

相关心智模型:
  • 服务歌优先于服务技术 (serve the song): 技术、音色、个人风格全都服从于"这首歌要表达什么"——好不好的最终裁判是情绪与歌本身，不是参数表（"if it sounds good, it is good"）。
  • 减法优先 / 每个处理都要能说出理由 (less but knowing why): 默认不处理；做得太多而非太少是这一行最常见的病——加任何东西（轨/EQ/压缩/响度）之前，先确认能不能减、不加，且每一次处理都要能讲出"我为什么这么做"。

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**comping（拼最佳 take）**: 用 take folder/playlist 把多条 take 逐句挑出最佳片段拼成一条。跳过 → 用了带瑕疵的整条 take，或浪费了录的多条素材。(evidence: [T03-S002])"
  "**time-align / 对齐**: 对齐双轨人声、和声、多话筒鼓（相位/时值），修明显抢拍/拖拍。跳过 → 双轨发虚/相位抵消，节奏松散。(evidence: [T03-S002])"
  "**quantize（编程/鼓节奏对齐）**: 把编程或录的鼓对齐网格，但按需保留 swing/groove。跳过 → 节奏飘，但**过度**量化又会丢 pocket（见资深差异）。(evidence: [T03-S010], pocket/quantize T06)"
  "**pitch-correct（修音）**: 用 Auto-Tune（实时/音染）或 Melodyne（离线/透明/复音）修音高。跳过 → 走音留在成品；但过度修又\"塑料感\"。(evidence: [T03-S002], Auto-Tune/Melodyne T02-S014)"
  "**清理 + crossfade + 去呼吸/噪声**: 剪头尾、加 crossfade 防爆音、处理明显呼吸/咔哒。跳过 → 混音里到处是爆音/杂音，分心又难定位。"
)
declare -a FAILURE_MODES=(
  "**过度修音（over-tuning）出塑料感**: 触发原因 = 逐音拉到 0 cent、retune speed 拉满。**CLI 化暗示**: 检查项「修完的人声还有没有情绪/呼吸？bypass A/B 一下，是不是修没了人味？」。"
  "**过度量化丢 pocket**: 触发原因 = 100% quantize 到网格，groove 死掉。**CLI 化暗示**: 检查项「量化后节奏还 swing 吗？还是变得机械？需要的话调 quantize strength < 100%」。"
  "**没加 crossfade / 没清理 → 爆音**: 触发原因 = comp 拼接处硬切。**CLI 化暗示**: 检查项「所有 comp 拼接点是否都有 crossfade？头尾是否清理过？」。"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "editing-comping-quantize-pitch-c-walkthrough"
fi
